insert into menu_items (id, name, description, category, parent_category, is_veg, is_available, sort_order) values
  ('3dd077ea-b036-58f0-9a3b-dab3746e894c', 'Espresso', 'Espresso is a meticulously extracted, full-bodied coffee with a rich crema, delivering an intense aroma, deep complexity, and a smooth, lingering finish.', 'Coffee', 'Hot', true, true, 0),
  ('fe41487c-d443-5467-9007-fa4f1a292be6', 'Americano', 'An Americano is a smooth and balanced coffee, made by blending rich espresso with hot water for a bold yet mellow flavor.', 'Coffee', 'Hot', true, true, 10),
  ('1e25a1e5-beaf-5603-9774-b742a56c75a2', 'Long Black', 'A Long Black is a rich and aromatic coffee, made by pouring smooth espresso over hot water to preserve its crema and bold flavor.', 'Coffee', 'Hot', true, true, 20),
  ('0b2c8ba9-5d0f-5738-91f6-a7f59a49e82f', 'Macchiato', 'A macchiato is a bold espresso lightly marked with a touch of velvety milk, delivering a rich, intense flavor with a smooth finish. Note: Please be aware that micro-foam may not retain its texture as effectively during transit in a sealed takeaway cup. The delicate foam, created by incorporating air, can gradually dissipate over time.', 'Coffee', 'Hot', true, true, 30),
  ('0b5dfda3-043c-5880-bb2a-c68508da02f8', 'Cappucino', 'A Cappucino is a harmonious blend of rich espresso, velvety steamed milk, and silky micro-foam for a perfectly balanced indulgence. Note: Please be aware that micro-foam may not retain its texture as effectively during transit in a sealed takeaway cup. The delicate foam, created by incorporating air, can gradually dissipate over time.', 'Coffee', 'Hot', true, true, 40),
  ('0b398e3e-a5b6-5e22-97f3-4a9852293ba2', 'Latte', 'A Latte is a luxurious blend of rich espresso and velvety steamed milk, topped with a silky microfoam for a smooth, balanced taste. Note: Please be aware that micro-foam may not retain its texture as effectively during transit in a sealed takeaway cup. The delicate foam, created by incorporating air, can gradually dissipate over time.', 'Coffee', 'Hot', true, true, 50),
  ('f10da810-119d-5015-b6a4-83751c3dedd2', 'Signature Mocha', 'A Signature Mocha is a decadent blend of rich espresso, velvety steamed milk, and luxurious chocolate, topped with a silky layer of foam for a perfect balance of sweetness and depth. Note: Please be aware that micro-foam may not retain its texture as effectively during transit in a sealed takeaway cup. The delicate foam, created by incorporating air, can gradually dissipate over time.', 'Coffee', 'Hot', true, true, 60),
  ('fe0ca015-9a8e-5cd2-bd1b-c4f0db7b4787', 'Flat White', 'A Flat White is a meticulously crafted coffee with a rich espresso base, seamlessly blended with velvety microfoam for a smooth, intense flavor experience. Note: Please be aware that micro-foam may not retain its texture as effectively during transit in a sealed takeaway cup. The delicate foam, created by incorporating air, can gradually dissipate over time.', 'Coffee', 'Hot', true, true, 70),
  ('dd1b2f19-315f-5178-b3a2-17ed49ea0bf8', 'Vietnamese Latte', 'A Vietnamese Latte is a rich and indulgent blend of robust espresso, sweetened condensed milk, and velvety steamed milk, offering a perfect harmony of creamy sweetness and bold flavor. Note: Please be aware that micro-foam may not retain its texture as effectively during transit in a sealed takeaway cup. The delicate foam, created by incorporating air, can gradually dissipate over time.', 'Coffee', 'Hot', true, true, 80),
  ('37bf6600-5d07-5fa9-8a54-0e2c88bbdd03', 'Lotus Biscoff Latte', 'A Lotus Biscoff Latte with spread is a decadent fusion of smooth espresso, creamy steamed milk, and a generous swirl of Biscoff spread, topped with crushed cookies for an irresistible, indulgent experience. Note: Please be aware that micro-foam may not retain its texture as effectively during transit in a sealed takeaway cup. The delicate foam, created by incorporating air, can gradually dissipate over time.', 'Coffee', 'Hot', true, true, 90),
  ('94c5bb54-ea27-57e8-8d7f-67f177600e8e', 'Honey Cinnamon', 'A Honey Cinnamon Latte blends rich espresso with velvety steamed milk, enhanced by the warmth of honey and a sprinkle of aromatic cinnamon for a comforting, sweet-spiced treat. Note: Please be aware that micro-foam may not retain its texture as effectively during transit in a sealed takeaway cup. The delicate foam, created by incorporating air, can gradually dissipate over time.', 'Coffee', 'Hot', true, true, 100),
  ('ccadd141-90c7-5f9e-bf16-0527fe847bc4', 'Rose Latte', 'A Rose Latte is a delicate fusion of smooth espresso, steamed milk, and aromatic rose syrup, creating a fragrant and subtly floral flavor experience. Note: Please be aware that micro-foam may not retain its texture as effectively during transit in a sealed takeaway cup. The delicate foam, created by incorporating air, can gradually dissipate over time.', 'Coffee', 'Hot', true, true, 110),
  ('bf7f32a3-5801-54b1-ad09-da08b45fc57c', 'White Mocha', 'A White Mocha is a luxurious blend of rich espresso, velvety steamed milk, and sweet white chocolate, creating a creamy and indulgent coffee experience. Note: Please be aware that micro-foam may not retain its texture as effectively during transit in a sealed takeaway cup. The delicate foam, created by incorporating air, can gradually dissipate over time.', 'Coffee', 'Hot', true, true, 120),
  ('79a02128-f81c-5615-9db7-bfd6a98eb873', 'Matcha Latte', 'A Matcha Latte combines finely ground matcha green tea with smooth steamed milk, offering a vibrant, earthy flavor and a creamy, soothing finish. Note: Please be aware that micro-foam may not retain its texture as effectively during transit in a sealed takeaway cup. The delicate foam, created by incorporating air, can gradually dissipate over time.', 'Hot Non-Coffee', 'Hot', true, true, 0),
  ('e784a84a-7fac-58a9-afc4-84cc28d4165c', 'Chai Latte', 'A Chai Latte is a warming blend of spiced chai tea and creamy steamed milk, offering a perfect balance of bold spices and smooth, comforting flavor. Note: Please be aware that micro-foam may not retain its texture as effectively during transit in a sealed takeaway cup. The delicate foam, created by incorporating air, can gradually dissipate over time.', 'Hot Non-Coffee', 'Hot', true, true, 10),
  ('a4fd6d6f-bcfb-5e7a-bc34-5317e15676c7', 'Pistachio Latte', 'A Pistachio Latte is a creamy blend of steamed milk and pistachio syrup, offering a smooth, nutty flavor with a rich, indulgent finish. Note: Please be aware that micro-foam may not retain its texture as effectively during transit in a sealed takeaway cup. The delicate foam, created by incorporating air, can gradually dissipate over time.', 'Hot Non-Coffee', 'Hot', true, true, 20),
  ('145e4b28-3a3c-581d-962a-7e46178e57d7', 'Signature Hot Chocolate', 'A Signature Hot Chocolate is a rich and indulgent blend of smooth milk and premium chocolate, topped with velvety foam for a comforting, luxurious treat.', 'Hot Non-Coffee', 'Hot', true, true, 30),
  ('dc447588-fcea-557e-9325-dac7ed3e3667', 'Hazelnut Hot Chocolate', 'A Hazelnut Hot Chocolate is a luxurious blend of rich chocolate, creamy milk, and the sweet, nutty crunch of Hazelnuts, creating a comforting and indulgent treat.', 'Hot Non-Coffee', 'Hot', true, true, 40),
  ('1af9bf90-8cf9-5a52-be1a-7ee64c853d32', 'Hioc''s Signature Creme', 'Hioc Signature Crème is a velvety, creamy cold coffee crafted from our bold Signature Espresso.', 'Creme Coffee', 'Creme', true, true, 0),
  ('233ee806-30a4-5de5-bd5c-0cdfeda68edc', 'Hazelnut Creme', 'Hazelnut Crème is a velvety, creamy cold coffee infused with the rich flavor of roasted hazelnuts, topped with a smooth, creamy whip.', 'Creme Coffee', 'Creme', true, true, 10),
  ('01f78b80-e545-5814-b50d-34b84d650d63', 'Caramel Creme', 'Caramel Crème is a rich, creamy cold coffee blended with sweet caramel, topped with a smooth, creamy whip.', 'Creme Coffee', 'Creme', true, true, 20),
  ('91c95277-9b4c-550d-9918-43e3279567ff', 'Chocochip Creme', 'Chocochip Crème is a indulgent cold coffee with a perfect blend of chocolate chips, finished with a creamy, smooth whip.', 'Creme Coffee', 'Creme', true, true, 30),
  ('badf3141-306c-5e55-893d-82fa8619b6a4', 'Caramel Chip Creme', 'Caramel Chip Crème is a delicious cold coffee with a perfect mix of caramel and crunchy caramel chips, topped with a creamy, smooth whip.', 'Creme Coffee', 'Creme', true, true, 40),
  ('dfaad0d0-f894-5fb6-b939-1614b2ab095f', 'Cookie Crumble Creme', 'Cookie Crème is a dreamy cold coffee, infused with crushed cookies for a sweet, crunchy texture, and topped with a generous swirl of velvety, creamy whip.', 'Creme Coffee', 'Creme', true, true, 50),
  ('707b512a-23b8-5f11-b6c5-852f1440e5e6', 'Lotus Biscoff Creme', 'Lotus Biscoff Crème is a rich cold coffee infused with the distinctive flavor of Lotus Biscoff biscuits, topped with a smooth, creamy whip for the perfect indulgence.', 'Creme Coffee', 'Creme', true, true, 60),
  ('980e1bf4-1c43-595f-86eb-6f4e28806a44', 'Blueberry Cheesecake Creme', 'Blueberry Cheesecake Crème is a rich, creamy blend with the tangy sweetness of blueberry cheesecake, finished with a smooth, velvety whip for the ultimate indulgence.', 'Creme Non-Coffee', 'Creme', true, true, 0),
  ('a7018a27-9df6-5c8a-8f85-fc3030d98f16', 'Strawberry Cheesecake Creme', 'Strawberry Cheesecake Crème is a creamy, indulgent blend with the sweet and tangy flavors of strawberry cheesecake, topped with a smooth, velvety whip for a luscious treat.', 'Creme Non-Coffee', 'Creme', true, true, 10),
  ('a97a21d8-6530-5fad-83a2-8e791fb692ce', 'Fruity Strawberry Creme', 'Strawberry Crème is a creamy cold drink infused with the fresh, sweet flavor of strawberries, topped with a smooth, velvety whip for a refreshing indulgence."', 'Creme Non-Coffee', 'Creme', true, true, 20),
  ('62869eb0-9080-5867-a363-d50b216fb01e', 'Fruity Mango Creme', 'Mango Crème is a rich, creamy blend with the tropical sweetness of ripe mangoes, topped with a smooth, velvety whip for a refreshing and indulgent treat.', 'Creme Non-Coffee', 'Creme', true, true, 30),
  ('0d34483d-4697-5f4d-a1ed-7a1bcfe74575', 'Oreo Creme', 'Oreo Crème is a rich, velvety blend of crushed Oreo cookies and decadent chocolate, creating a creamy, irresistible treat.', 'Creme Non-Coffee', 'Creme', true, true, 40),
  ('d15ca93e-96d7-5cd2-8fac-c8994a2e71bd', 'Signature Chocolate Creme', 'Signature Chocolate Crème is a luxurious, creamy blend of rich chocolate and smooth espresso, creating the perfect indulgent treat.', 'Creme Non-Coffee', 'Creme', true, true, 50),
  ('f7d1a343-e449-5537-94e9-f50da014ef90', 'Krazy Kitkat Creme', 'Krazy Kitkat Crème is a fun, creamy blend with crunchy KitKat pieces and smooth chocolate, delivering an irresistible, indulgent treat.', 'Creme Non-Coffee', 'Creme', true, true, 60),
  ('d3541394-10ce-5ad8-96f5-e90c5b575903', 'Matcha Creme', 'Matcha Crème is a velvety, creamy blend of finely ground green tea leaves, offering a rich, earthy flavor balanced with a smooth, indulgent texture for a refreshing and unique treat.', 'Creme Non-Coffee', 'Creme', true, true, 70),
