  ('f1828980-8045-5908-9c78-7cfea73cdd15', 'On The Rocks', 'On the Rocks Espresso is a bold and smooth coffee served over chilled cubes for a crisp and invigorating experience.', 'Iced Coffee', 'Iced Drinks', true, true, 0),
  ('df78b99a-ef7d-58ae-9c7f-b6a6bc65bbb2', 'Americano Iced', 'Iced Americano is a classic espresso blended with chilled water, delivering a refreshing and light coffee flavor with a cooling edge.', 'Iced Coffee', 'Iced Drinks', true, true, 10),
  ('32a41b58-fb6e-51c5-bb5f-8aa53d65f22d', 'Long Black Iced', 'Iced Long Black is a rich and full-bodied coffee combined with chilled water, offering a robust and refreshing drink.', 'Iced Coffee', 'Iced Drinks', true, true, 20),
  ('754498a2-fe7e-5c4c-a2e9-b3f868b7592f', 'Cappucino Iced', 'Iced Cappuccino blends velvety espresso with frothy milk and a cool layer of ice, creating a creamy twist on the classic cappuccino.', 'Iced Coffee', 'Iced Drinks', true, true, 30),
  ('fe5ee148-2d0f-52c4-9398-7c4e5bee6dee', 'Latte Iced', 'Iced Latte is a smooth espresso paired with creamy chilled milk and complemented by ice for a perfectly balanced coffee.', 'Iced Coffee', 'Iced Drinks', true, true, 40),
  ('cef3e25c-3466-5405-97fe-c0cd7f0d09f0', 'Vietnamese Latte Iced', 'Iced Vietnamese Latte combines bold espresso with sweet condensed milk, finished with a touch of ice for a creamy and indulgent treat.', 'Iced Coffee', 'Iced Drinks', true, true, 50),
  ('3b5a1702-44ef-5bc6-8751-eefcfe988686', 'Signature Mocha Iced', 'Iced Signature Mocha is a decadent mix of rich espresso and smooth chocolate, balanced with creamy milk and served with ice for a luxurious coffee moment.', 'Iced Coffee', 'Iced Drinks', true, true, 60),
  ('087ee0d3-0c36-5e34-a49e-8ccd93840338', 'Cranberry Iced', 'Cranberry Coffee is a unique fusion of bold coffee and tangy cranberry, paired with ice for a refreshing, fruity twist.', 'Iced Coffee', 'Iced Drinks', true, true, 70),
  ('7c245809-e627-54af-9004-ad6925da16d4', 'Valencia Orange Iced', 'Valencia Orange Coffee is a vibrant blend of espresso and zesty Valencia orange, complemented by ice for a refreshing, citrusy experience.', 'Iced Coffee', 'Iced Drinks', true, true, 80),
