  ('be790e9b-6e7c-52c2-a6b8-a59515f32623', 'Tripple Choco', 'Triple Choco Waffle is a decadent treat featuring a soft vanilla waffle base, generously topped with creamy milk chocolate and artfully drizzled with rich dark and silky white liquid chocolate for the ultimate chocolate lover''s delight.', 'Stick Waffles', '', true, true, 0),
  ('d36ff0fc-1b31-5443-bf09-09730718d3a7', 'Choco-Chips', 'Choco-Chips Waffle is a chocolate lover''s dream with a rich chocolate waffle base, topped with smooth milk chocolate, sprinkled with dark and white chocolate chips, and finished with a drizzle of dark chocolate.', 'Stick Waffles', '', true, true, 10),
  ('c4c7a9fa-b903-5f6d-94ee-f00f954432f0', 'Dark Fantasy', 'Dark Fantasy Waffle is an indulgent delight with a rich chocolate waffle base, topped with luscious dark chocolate and sprinkled with crunchy dark chocolate chips for an intense chocolate experience.', 'Stick Waffles', '', true, true, 20),
  ('dc622403-ce78-576a-99b4-513107fdc8dc', 'White Garland', 'White Garland Waffle is a heavenly creation with a vibrant red velvet waffle base, topped with creamy white chocolate and adorned with delicate white chocolate chips for a perfectly elegant treat.', 'Stick Waffles', '', true, true, 30),
  ('249b79d2-36c9-55d0-9b7c-6c45822ca44e', 'Signature Choco', 'Signature Choco Waffle is a classic indulgence featuring a soft vanilla waffle base, topped with smooth milk chocolate and finished with a rich drizzle of dark chocolate.', 'Stick Waffles', '', true, true, 40),
  ('cae51448-75c4-5c5f-bc88-68272a861a05', 'Almond Honey', 'Almond Honey Waffle is a delightful combination of a soft vanilla and almond waffle base, topped with sweet, golden honey and garnished with crunchy almond slivers for a perfect balance of sweetness and crunch.', 'Stick Waffles', '', true, true, 50),
  ('748d9739-c8a7-54af-be21-d59684ce5d3c', 'Black Forest', 'Black Forest Waffle features a soft vanilla waffle base, topped with rich dark chocolate, sprinkled with dark chocolate chips, and finished with a drizzle of silky white chocolate for a perfect balance of flavors.', 'Stick Waffles', '', true, true, 60),
  ('5131e1d2-1284-556d-8390-1a560dae0f0e', 'Oreo-Heaven', 'Oreo-Heaven Waffle is a dreamy treat with a vanilla and Oreo-infused waffle base, topped with smooth white chocolate, finished with crushed Oreo pieces, and drizzled with rich dark chocolate for the ultimate indulgence.', 'Stick Waffles', '', true, true, 70),
  ('40337109-bd1e-558d-9c22-a0d9f6f55a19', 'Cinoffle', 'Cinoffle Waffle combines a warm vanilla and cinnamon-infused waffle base, topped with smooth white chocolate, garnished with a sprinkle of cinnamon, and finished with a drizzle of rich dark chocolate for a cozy, flavorful treat.', 'Stick Waffles', '', true, true, 80),
  ('15be1217-ead5-5846-a9bd-8276abbc120c', 'Krazy Kit-kat', 'Krazy Kitkat Waffle features a soft vanilla waffle base, topped with smooth milk chocolate, loaded with crunchy KitKat chunks, and finished with a drizzle of creamy milk chocolate for the perfect combination of sweetness and crunch.', 'Stick Waffles', '', true, true, 90),
  ('4a71d039-b9bf-5fcd-a32e-d17ad6d4a7db', 'Butterscotch', 'Butterscotch Waffle is a delightful treat with a soft vanilla waffle base, topped with smooth white chocolate, finished with crunchy caramel bits, and drizzled with rich caramel for a perfect balance of sweetness and texture.', 'Stick Waffles', '', true, true, 100),
  ('18c3e9df-c86d-534b-9c35-3cd7d220274e', 'Nutella', 'Nutella Waffle features a soft vanilla waffle base, topped with creamy Nutella, and finished with a rich drizzle of both dark and milk chocolate for a perfectly indulgent treat.', 'Stick Waffles', '', true, true, 110),
  ('f42d53fc-d07e-5349-9bfa-72bd8ff99c2c', 'Nutella-Almond', 'Nutella-Almond Waffle features a soft vanilla and almond-infused waffle base, topped with creamy Nutella and finished with crunchy almond slivers for a delightful balance of smooth and nutty flavors.', 'Stick Waffles', '', true, true, 120),
  ('d45ad8ff-942f-5f7c-b72c-7357fb414d91', 'Nutella-Hazelnut', 'Nutella-Hazelnut Waffle features a soft vanilla and hazelnut-infused waffle base, topped with creamy Nutella and finished with crunchy hazelnuts for a perfect blend of smooth chocolate and nutty texture.', 'Stick Waffles', '', true, true, 130),
