  ('672bb1a8-90ef-5036-bbd7-932a0020e728', 'Vanilla Creme Cold Brew', 'Vanilla Crème Cold Brew is a smooth, rich cold brew coffee, steeped for 18-24 hours and infused with a hint of vanilla, topped with a creamy, velvety finish for a refreshing and indulgent experience.', 'Cold Brews', '', true, true, 10),
  ('4f728165-d097-5915-b7ac-07eaad3230ce', 'Toffee Nut Cold Brew', 'Toffee Nut Cold Brew is a smooth, rich cold brew coffee, steeped for 18-24 hours, infused with the sweet flavors of caramel and a hint of hazelnut, topped with a creamy finish for a deliciously nutty and indulgent experience.', 'Cold Brews', '', true, true, 20),
